// ═══════════════════════════════════════════════════
// Linear Webhook Signature Verification & Parsing
// RSP_001 | NOIZY Empire | Linear Integration
// ═══════════════════════════════════════════════════
const crypto = require('crypto');

const body = $input.first().json;
const rawBody = $input.first().json.body || JSON.stringify(body);
const signature = $input.first().json.headers?.['linear-signature'] || '';
const secret = $env.LINEAR_WEBHOOK_SECRET || '';

// Verify webhook signature if secret is configured
if (secret && signature) {
  const hmac = crypto.createHmac('sha256', secret);
  hmac.update(typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody));
  const expected = hmac.digest('hex');
  if (signature !== expected) {
    return [{ json: { error: 'Invalid signature', _reject: true } }];
  }
}

// Parse Linear webhook payload
const action = body.action; // 'create', 'update', 'remove'
const type = body.type;     // 'Issue', 'Comment', 'Project', etc.
const data = body.data || {};

const event = {
  source: 'linear',
  action: action,
  type: type,
  issue_id: data.id,
  issue_title: data.title || '',
  issue_description: data.description || '',
  issue_state: data.state?.name || '',
  issue_priority: data.priority || 0,
  issue_labels: (data.labels || []).map(l => l.name),
  assignee: data.assignee?.name || '',
  project: data.project?.name || '',
  team: data.team?.name || '',
  url: data.url || '',
  created_at: data.createdAt || '',
  updated_at: data.updatedAt || new Date().toISOString(),
  // NOIZY governance fields
  governance_cleared: true,
  processed_at: new Date().toISOString()
};

return [{ json: event }];

// ═══════════════════════════════════════════════════
// New Issue → Create GitHub Branch + Notion Task
// ═══════════════════════════════════════════════════
const event = $input.first().json;

// Generate branch name from Linear issue
const branchName = `linear/${event.issue_id?.substring(0,8) || 'unknown'}/${(event.issue_title || 'task').toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 40)}`;

return [{
  json: {
    ...event,
    branch_name: branchName,
    // Notion page properties
    notion_page: {
      'Task': { title: [{ text: { content: `[Linear] ${event.issue_title}` } }] },
      'Status': { select: { name: 'To Do' } },
      'Source': { select: { name: 'Linear' } },
      'Priority': { select: { name: event.issue_priority <= 1 ? 'Urgent' : event.issue_priority <= 2 ? 'High' : 'Medium' } },
      'Linear URL': { url: event.url },
      'Assignee': { rich_text: [{ text: { content: event.assignee } }] },
      'Created': { date: { start: event.created_at || new Date().toISOString() } }
    }
  }
}];

// ═══════════════════════════════════════════════════
// Issue Updated → Sync state to Notion + notify GABRIEL
// ═══════════════════════════════════════════════════
const event = $input.first().json;

// Map Linear states to Notion statuses
const stateMap = {
  'Backlog': 'Backlog',
  'Todo': 'To Do',
  'In Progress': 'In Progress',
  'In Review': 'In Review',
  'Done': 'Done',
  'Canceled': 'Archived'
};

const notionStatus = stateMap[event.issue_state] || event.issue_state;

return [{
  json: {
    ...event,
    notion_status: notionStatus,
    gabriel_alert: {
      type: 'linear_update',
      summary: `Linear issue "${event.issue_title}" moved to ${event.issue_state}`,
      severity: event.issue_priority <= 1 ? 'high' : 'low',
      source: 'linear',
      timestamp: new Date().toISOString()
    }
  }
}];

// ═══════════════════════════════════════════════════
// Issue Done → Close loop, update Notion, log to ledger
// ═══════════════════════════════════════════════════
const event = $input.first().json;

return [{
  json: {
    ...event,
    completion: {
      issue_title: event.issue_title,
      completed_at: new Date().toISOString(),
      assignee: event.assignee,
      // Ledger entry for consent/governance tracking
      ledger_entry: {
        action: 'task_completed',
        source: 'linear',
        actor: event.assignee,
        subject: event.issue_title,
        timestamp: new Date().toISOString(),
        governance_status: 'cleared'
      }
    }
  }
}];

