// ═══════════════════════════════════════════════════
// Transform Linear poll results into GABRIEL events
// ═══════════════════════════════════════════════════
const response = $input.first().json;
const issues = response.data?.issues?.nodes || [];

if (issues.length === 0) {
  return [{ json: { _skip: true, message: 'No recent updates' } }];
}

const events = issues.map(issue => ({
  source: 'linear-poll',
  type: 'Issue',
  action: 'sync',
  issue_id: issue.id,
  issue_title: issue.title,
  issue_state: issue.state?.name || '',
  issue_priority: issue.priority || 0,
  assignee: issue.assignee?.name || '',
  project: issue.project?.name || '',
  url: issue.url,
  labels: (issue.labels?.nodes || []).map(l => l.name),
  updated_at: issue.updatedAt
}));

return events.map(e => ({ json: e }));
